import { MiniCompletedRow } from './MiniCompletedRow'
import { GameState } from '../../lib/localStorage'

type Props = {
  state: GameState
}

export const MiniGrid = ({ state }: Props) => {
  return (
    <div className="pb-6">
      {state.guesses.map((guess, i) => (
        <MiniCompletedRow key={i} guess={guess} solution={state.solution} />
      ))}
    </div>
  )
}
