import { GameState } from './localStorage'
import { getGuessStatuses } from './statuses'

export const shareStatus = (state: GameState) => {
  navigator.clipboard.writeText(
    `Haseła ${state.solutionIndex} ${state.guesses.length}/6\n\n` +
      generateEmojiGrid(state)
  )
}

export const generateEmojiGrid = (state: GameState) => {
  return state.guesses
    .map((guess) => {
      const status = getGuessStatuses(guess, state.solution)
      return guess
        .split('')
        .map((letter, i) => {
          switch (status[i]) {
            case 'correct':
              return '🟩'
            case 'present':
              return '🟨'
            default:
              return '⬜'
          }
        })
        .join('')
    })
    .join('\n')
}
