import { CompletedRow } from './CompletedRow'
import { CurrentRow } from './CurrentRow'
import { EmptyRow } from './EmptyRow'
import { GameState } from '../../lib/localStorage'

type Props = {
  state: GameState
  currentGuess: string
}

export const Grid = ({ state, currentGuess }: Props) => {
  const empties =
    state.guesses.length < 5 ? Array.from(Array(5 - state.guesses.length)) : []

  return (
    <div className="pb-6">
      {state.guesses.map((guess, i) => (
        <CompletedRow key={i} guess={guess} solution={state.solution} />
      ))}
      {state.guesses.length < 6 && <CurrentRow guess={currentGuess} />}
      {empties.map((_, i) => (
        <EmptyRow key={i} />
      ))}
    </div>
  )
}
