import {
  ChartBarIcon,
  InformationCircleIcon,
  RefreshIcon,
} from '@heroicons/react/outline'
import { useState, useEffect } from 'react'
import { Alert } from './components/alerts/Alert'
import { Grid } from './components/grid/Grid'
import { Keyboard } from './components/keyboard/Keyboard'
import { AboutModal } from './components/modals/AboutModal'
import { InfoModal } from './components/modals/InfoModal'
import { WinModal } from './components/modals/WinModal'
import { StatsModal } from './components/modals/StatsModal'
import { isWordInWordList, newGameState } from './lib/words'
import { addStatsForCompletedGame, loadStats } from './lib/stats'
import {
  loadGameStateFromLocalStorage,
  saveGameStateToLocalStorage,
  GameState,
} from './lib/localStorage'

function App() {
  const [currentGuess, setCurrentGuess] = useState('')
  const [isGameWon, setIsGameWon] = useState(false)
  const [isWinModalOpen, setIsWinModalOpen] = useState(false)
  const [isInfoModalOpen, setIsInfoModalOpen] = useState(false)
  const [isAboutModalOpen, setIsAboutModalOpen] = useState(false)
  const [isNotEnoughLetters, setIsNotEnoughLetters] = useState(false)
  const [isStatsModalOpen, setIsStatsModalOpen] = useState(false)
  const [isWordNotFoundAlertOpen, setIsWordNotFoundAlertOpen] = useState(false)
  const [isGameLost, setIsGameLost] = useState(false)
  const [shareComplete, setShareComplete] = useState(false)
  const [state, setGameState] = useState<GameState>(() => {
    const loaded = loadGameStateFromLocalStorage()
    if (!loaded) {
      const newState = newGameState()
      saveGameStateToLocalStorage(newState)
      return newState
    }
    const gameWasWon = loaded.guesses.includes(loaded.solution)
    if (gameWasWon) {
      setIsGameWon(true)
    }
    if (loaded.guesses.length === 6 && !gameWasWon) {
      setIsGameLost(true)
    }
    return loaded
  })

  const [stats, setStats] = useState(() => loadStats())

  useEffect(() => {
    saveGameStateToLocalStorage(state)
  })

  useEffect(() => {
    if (isGameWon) {
      setIsWinModalOpen(true)
    }
  }, [isGameWon])

  const onChar = (value: string) => {
    if (currentGuess.length < 5 && state.guesses.length < 6 && !isGameWon) {
      setCurrentGuess(`${currentGuess}${value}`)
    }
  }

  const onDelete = () => {
    setCurrentGuess(currentGuess.slice(0, -1))
  }

  const onEnter = () => {
    if (!(currentGuess.length === 5) && !isGameLost) {
      setIsNotEnoughLetters(true)
      return setTimeout(() => {
        setIsNotEnoughLetters(false)
      }, 2000)
    }

    if (!isWordInWordList(currentGuess)) {
      setIsWordNotFoundAlertOpen(true)
      return setTimeout(() => {
        setIsWordNotFoundAlertOpen(false)
      }, 2000)
    }

    const winningWord = currentGuess === state.solution

    if (currentGuess.length === 5 && state.guesses.length < 6 && !isGameWon) {
      setGameState({ ...state, guesses: [...state.guesses, currentGuess] })
      setCurrentGuess('')

      if (winningWord) {
        setStats(addStatsForCompletedGame(stats, state.guesses.length))
        return setIsGameWon(true)
      }

      if (state.guesses.length === 5) {
        setStats(addStatsForCompletedGame(stats, state.guesses.length + 1))
        setIsGameLost(true)
        setTimeout(() => {
          setIsGameLost(false)
        }, 10000)
      }
    }
  }

  return (
    <div className="py-8 max-w-7xl mx-auto sm:px-6 lg:px-8">
      <div className="flex w-80 mx-auto items-center mb-8">
        <h1 className="text-xl grow font-bold">Haseła</h1>
        <span title="Nowa gra">
          <RefreshIcon
            className="h-6 w-6 cursor-pointer"
            onClick={() => {
              setGameState(newGameState())
              setIsGameLost(false)
              setIsGameWon(false)
              setCurrentGuess('')
            }}
          />
        </span>
        <span title="Instrukcja">
          <InformationCircleIcon
            className="h-6 w-6 cursor-pointer"
            onClick={() => setIsInfoModalOpen(true)}
          />
        </span>
        <span title="Statystyki">
          <ChartBarIcon
            className="h-6 w-6 cursor-pointer"
            onClick={() => setIsStatsModalOpen(true)}
          />
        </span>
      </div>
      <Grid state={state} currentGuess={currentGuess} />
      <Keyboard
        onChar={onChar}
        onDelete={onDelete}
        onEnter={onEnter}
        state={state}
      />
      <WinModal
        isOpen={isWinModalOpen}
        handleClose={() => setIsWinModalOpen(false)}
        state={state}
        handleShare={() => {
          setIsWinModalOpen(false)
          setShareComplete(true)
          return setTimeout(() => {
            setShareComplete(false)
          }, 2000)
        }}
      />
      <InfoModal
        isOpen={isInfoModalOpen}
        handleClose={() => setIsInfoModalOpen(false)}
      />
      <StatsModal
        isOpen={isStatsModalOpen}
        handleClose={() => setIsStatsModalOpen(false)}
        gameStats={stats}
      />
      <AboutModal
        isOpen={isAboutModalOpen}
        handleClose={() => setIsAboutModalOpen(false)}
      />

      <button
        type="button"
        className="mx-auto mt-8 flex items-center px-2.5 py-1.5 border border-transparent text-xs font-medium rounded text-indigo-700 bg-indigo-100 hover:bg-indigo-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 select-none"
        onClick={() => setIsAboutModalOpen(true)}
      >
        Informacje o grze
      </button>

      <Alert message="Wpisz pięć liter" isOpen={isNotEnoughLetters} />
      <Alert message="Nie ma takiego słowa" isOpen={isWordNotFoundAlertOpen} />
      <Alert
        message={`Niestety przegrałeś, rozwiązanie to ${state.solution}. Może następnym razem pójdzie lepiej.`}
        isOpen={isGameLost}
      />
      <Alert
        message="Gra skopiowana do schowka"
        isOpen={shareComplete}
        variant="success"
      />
    </div>
  )
}

export default App
